const item = $input.first().json;
const context = item.run_context || {};
const lines = [
  `*${context.workflow_name || item.workflow_name || "Workflow"} — Run Summary*`,
  `Mode: ${context.mode || item.mode || "production"}`,
  `Trigger: ${context.trigger_type || item.trigger_type || "schedule"}`,
  `Dry run: ${context.dry_run || item.dry_run ? "yes" : "no"}`,
  item.summary_detail || "Completed shared workflow stages."
].filter(Boolean);
return [{ json: { ...item, summary_message: lines.join("\n"), delivery_target: { target_type: "channel", target_id: item.summary_channel_id || item.default_channel_id || "" } } }];
